     1→// app/(tabs)/index.tsx
     2→// Visual Novel Style Home Screen - With Settings Gear Icon
     3→
     4→import { Ionicons } from '@expo/vector-icons';
     5→import { LinearGradient } from 'expo-linear-gradient';
     6→import { useRouter } from 'expo-router';
     7→import { collection, deleteDoc, doc, getDocs, limit, onSnapshot, query, updateDoc, where } from 'firebase/firestore';
     8→import React, { useCallback, useEffect, useRef, useState } from 'react';
     9→import {
    10→  Animated,
    11→  Dimensions,
    12→  Pressable,
    13→  RefreshControl,
    14→  StatusBar,
    15→  StyleSheet,
    16→  Text,
    17→  View,
    18→} from 'react-native';
    19→import { useSafeAreaInsets } from 'react-native-safe-area-context';
    20→import ApexModal from '../../components/ApexModal';
    21→import SwipeableHabitCard from '../../components/SwipeableHabitCard';
    22→import { auth, db } from '../../config/firebase';
    23→import { BorderRadius, Colors, Shadows, Spacing } from '../../constants/theme';
    24→
    25→const { width: SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get('window');
    26→const CHARACTER_HEIGHT = 370; // BIGGER - takes up more screen
    27→
    28→// ============== HELPERS ==============
    29→
    30→function getLocalDateString(date: Date = new Date()): string {
    31→  const year = date.getFullYear();
    32→  const month = String(date.getMonth() + 1).padStart(2, '0');
    33→  const day = String(date.getDate()).padStart(2, '0');
    34→  return `${year}-${month}-${day}`;
    35→}
    36→
    37→function getYesterdayDateString(): string {
    38→  const yesterday = new Date();
    39→  yesterday.setDate(yesterday.getDate() - 1);
    40→  return getLocalDateString(yesterday);
    41→}
    42→
    43→function getTimeBasedGreeting(): string {
    44→  const hour = new Date().getHours();
    45→  if (hour >= 5 && hour < 12) return 'Morning';
    46→  if (hour >= 12 && hour < 17) return 'Afternoon';
    47→  if (hour >= 17 && hour < 22) return 'Evening';
    48→  return 'Late night';
    49→}
    50→
    51→function getMotivationalMessage(completed: number, total: number): string {
    52→  if (total === 0) return "Oi, you haven't set up any habits yet! Let's get you sorted, yeah?";
    53→  
    54→  const percentage = (completed / total) * 100;
    55→  const timeGreeting = getTimeBasedGreeting();
    56→  
    57→  if (completed === total) {
    58→    return `${timeGreeting}! You've smashed every single one today. Proper job, that is. Get some rest, champion.`;
    59→  }
    60→  
    61→  if (completed === 0) {
    62→    return `${timeGreeting}! Nothing done yet? Come on then, let's see what you're made of. Time to get moving!`;
    63→  }
    64→  
    65→  if (percentage >= 75) {
    66→    return `${timeGreeting}! ${completed} out of ${total} done - you're nearly there! Don't go soft on me now.`;
    67→  }
    68→  
    69→  if (percentage >= 50) {
    70→    return `${timeGreeting}! Halfway there with ${completed}/${total}. Keep that energy up, we're building momentum.`;
    71→  }
    72→  
    73→  return `${timeGreeting}! ${completed}/${total} complete. Still got work to do - let's crack on!`;
    74→}
    75→
    76→// ============== INTERFACES ==============
    77→
    78→interface Habit {
    79→  id: string;
    80→  name: string;
    81→  description: string;
    82→  currentStreak: number;
    83→  longestStreak: number;
    84→  totalCheckIns: number;
    85→  createdAt: string;
    86→  lastCheckIn?: string;
    87→  lastCheckInLocal?: string;
    88→}
    89→
    90→interface HabitWithDisplayStreak extends Habit {
    91→  displayStreak: number;
    92→}
    93→
    94→// ============== STREAK LOGIC ==============
    95→
    96→function isCompletedToday(habit: Habit): boolean {
    97→  const today = getLocalDateString();
    98→  if (habit.lastCheckInLocal) return habit.lastCheckInLocal === today;
    99→  if (habit.lastCheckIn) return habit.lastCheckIn.split('T')[0] === today;
   100→  return false;
   101→}
   102→
   103→function isCompletedYesterday(habit: Habit): boolean {
   104→  const yesterday = getYesterdayDateString();
   105→  if (habit.lastCheckInLocal) return habit.lastCheckInLocal === yesterday;
   106→  if (habit.lastCheckIn) return habit.lastCheckIn.split('T')[0] === yesterday;
   107→  return false;
   108→}
   109→
   110→function getDisplayStreak(habit: Habit): number {
   111→  if (isCompletedToday(habit)) return habit.currentStreak;
   112→  if (isCompletedYesterday(habit)) return habit.currentStreak;
   113→  return 0;
   114→}
   115→
   116→// ============== SETTINGS BUTTON COMPONENT ==============
   117→
   118→function SettingsButton({ onPress }: { onPress: () => void }) {
   119→  return (
   120→    <Pressable
   121→      style={({ pressed }) => [
   122→        settingsButtonStyles.container,
   123→        pressed && settingsButtonStyles.pressed,
   124→      ]}
   125→      onPress={onPress}
   126→    >
   127→      <Ionicons name="settings-outline" size={22} color={Colors.textPrimary} />
   128→    </Pressable>
   129→  );
   130→}
   131→
   132→const settingsButtonStyles = StyleSheet.create({
   133→  container: {
   134→    width: 40,
   135→    height: 40,
   136→    borderRadius: 20,
   137→    backgroundColor: 'rgba(0, 0, 0, 0.4)',
   138→    alignItems: 'center',
   139→    justifyContent: 'center',
   140→    borderWidth: 1,
   141→    borderColor: 'rgba(255, 255, 255, 0.1)',
   142→  },
   143→  pressed: {
   144→    backgroundColor: 'rgba(0, 0, 0, 0.6)',
   145→    transform: [{ scale: 0.95 }],
   146→  },
   147→});
   148→
   149→// ============== PROGRESS BAR COMPONENT ==============
   150→
   151→function WarmProgressBar({ completed, total }: { completed: number; total: number }) {
   152→  const percentage = total > 0 ? (completed / total) * 100 : 0;
   153→  
   154→  return (
   155→    <View style={progressStyles.container}>
   156→      <View style={progressStyles.labelRow}>
   157→        <Text style={progressStyles.label}>DAILY PROGRESS</Text>
   158→        <Text style={progressStyles.count}>
   159→          <Text style={progressStyles.countHighlight}>{completed}</Text>/{total}
   160→        </Text>
   161→      </View>
   162→      <View style={progressStyles.barBackground}>
   163→        <View style={[progressStyles.barFill, { width: `${percentage}%` }]} />
   164→        {total > 1 && Array.from({ length: total - 1 }).map((_, i) => (
   165→          <View
   166→            key={i}
   167→            style={[
   168→              progressStyles.segment,
   169→              { left: `${((i + 1) / total) * 100}%` }
   170→            ]}
   171→          />
   172→        ))}
   173→      </View>
   174→    </View>
   175→  );
   176→}
   177→
   178→const progressStyles = StyleSheet.create({
   179→  container: {
   180→    marginBottom: Spacing.lg,
   181→  },
   182→  labelRow: {
   183→    flexDirection: 'row',
   184→    justifyContent: 'space-between',
   185→    alignItems: 'center',
   186→    marginBottom: Spacing.sm,
   187→  },
   188→  label: {
   189→    fontSize: 11,
   190→    fontWeight: '600',
   191→    color: Colors.textMuted,
   192→    letterSpacing: 2,
   193→  },
   194→  count: {
   195→    fontSize: 14,
   196→    fontWeight: '500',
   197→    color: Colors.textMuted,
   198→  },
   199→  countHighlight: {
   200→    color: Colors.accent,
   201→    fontWeight: '700',
   202→  },
   203→  barBackground: {
   204→    height: 8,
   205→    backgroundColor: Colors.incomplete,
   206→    borderRadius: 4,
   207→    overflow: 'hidden',
   208→    position: 'relative',
   209→  },
   210→  barFill: {
   211→    position: 'absolute',
   212→    left: 0,
   213→    top: 0,
   214→    bottom: 0,
   215→    backgroundColor: Colors.accent,
   216→    borderRadius: 4,
   217→  },
   218→  segment: {
   219→    position: 'absolute',
   220→    top: 0,
   221→    bottom: 0,
   222→    width: 2,
   223→    backgroundColor: Colors.background,
   224→  },
   225→});
   226→
   227→// ============== DIALOGUE BOX COMPONENT ==============
   228→
   229→function DialogueBox({ message }: { message: string }) {
   230→  return (
   231→    <View style={dialogueStyles.container}>
   232→      <View style={dialogueStyles.nameplate}>
   233→        <Text style={dialogueStyles.nameplateText}>APEX LAD</Text>
   234→      </View>
   235→      
   236→      <View style={dialogueStyles.dialogueContent}>
   237→        <Text style={dialogueStyles.messageText}>{message}</Text>
   238→      </View>
   239→    </View>
   240→  );
   241→}
   242→
   243→const dialogueStyles = StyleSheet.create({
   244→  container: {
   245→    marginBottom: Spacing.xl,
   246→    ...Shadows.dialogue,
   247→  },
   248→  nameplate: {
   249→    position: 'absolute',
   250→    top: -12,
   251→    left: Spacing.lg,
   252→    backgroundColor: Colors.nameplateBackground,
   253→    paddingHorizontal: Spacing.md,
   254→    paddingVertical: Spacing.xs + 2,
   255→    borderRadius: BorderRadius.sm,
   256→    zIndex: 10,
   257→  },
   258→  nameplateText: {
   259→    fontSize: 11,
   260→    fontWeight: '700',
   261→    color: Colors.nameplateText,
   262→    letterSpacing: 2,
   263→  },
   264→  dialogueContent: {
   265→    backgroundColor: Colors.dialogueBackground,
   266→    borderWidth: 2,
   267→    borderColor: Colors.dialogueBorder,
   268→    borderRadius: BorderRadius.dialogue,
   269→    paddingTop: Spacing.xl,
   270→    paddingBottom: Spacing.lg,
   271→    paddingHorizontal: Spacing.lg,
   272→    minHeight: 90,
   273→  },
   274→  messageText: {
   275→    fontSize: 16,
   276→    fontWeight: '500',
   277→    color: Colors.textPrimary,
   278→    lineHeight: 24,
   279→  },
   280→});
   281→
   282→// ============== MAIN COMPONENT ==============
   283→
   284→export default function HomeScreen() {
   285→  const [habits, setHabits] = useState<HabitWithDisplayStreak[]>([]);
   286→  const [loading, setLoading] = useState(true);
   287→  const [refreshing, setRefreshing] = useState(false);
   288→  const scrollY = useRef(new Animated.Value(0)).current;
   289→  const router = useRouter();
   290→  const insets = useSafeAreaInsets();
   291→
   292→  const [modal, setModal] = useState({
   293→    visible: false,
   294→    mood: 'talking' as 'pleased' | 'talking',
   295→    title: '',
   296→    message: '',
   297→    buttonText: 'OK',
   298→  });
   299→
   300→  useEffect(() => {
   301→    const userId = auth.currentUser?.uid;
   302→    if (!userId) return;
   303→
   304→    const habitsRef = collection(db, 'users', userId, 'habits');
   305→    const q = query(habitsRef);
   306→
   307→    const unsubscribe = onSnapshot(q, (snapshot) => {
   308→      const habitsData: HabitWithDisplayStreak[] = [];
   309→      snapshot.forEach((docSnap) => {
   310→        const data = docSnap.data();
   311→        const habit = { id: docSnap.id, ...data } as Habit;
   312→        const displayStreak = getDisplayStreak(habit);
   313→        habitsData.push({ ...habit, displayStreak });
   314→      });
   315→      setHabits(habitsData);
   316→      setLoading(false);
   317→      setRefreshing(false);
   318→    });
   319→
   320→    return () => unsubscribe();
   321→  }, []);
   322→
   323→  useEffect(() => {
   324→    const userId = auth.currentUser?.uid;
   325→    if (!userId) return;
   326→
   327→    const checkDailyRoast = async () => {
   328→      try {
   329→        const roastsRef = collection(db, 'users', userId, 'dailyRoasts');
   330→        const q = query(roastsRef, where('read', '==', false), limit(1));
   331→        const snapshot = await getDocs(q);
   332→
   333→        if (!snapshot.empty) {
   334→          const roastDoc = snapshot.docs[0];
   335→          const roastData = roastDoc.data();
   336→          setModal({
   337→            visible: true,
   338→            mood: 'talking',
   339→            title: 'INCOMING MESSAGE',
   340→            message: roastData.message,
   341→            buttonText: 'GOT IT',
   342→          });
   343→          await updateDoc(roastDoc.ref, { read: true });
   344→        }
   345→      } catch (error) {
   346→        console.error('Error checking roast:', error);
   347→      }
   348→    };
   349→
   350→    const timer = setTimeout(checkDailyRoast, 1000);
   351→    return () => clearTimeout(timer);
   352→  }, []);
   353→
   354→  // Pass the ENTIRE habit object so check-in screen has all data immediately
   355→  const handleCheckIn = useCallback((habitId: string) => {
   356→    router.push(`/checkin/${habitId}`);
   357→  }, [router]);
   358→
   359→  const handleDeleteHabit = useCallback(async (habitId: string, habitName: string) => {
   360→    setModal({
   361→      visible: true,
   362→      mood: 'talking',
   363→      title: 'DELETE HABIT',
   364→      message: `Remove "${habitName}"? All progress will be lost.`,
   365→      buttonText: 'CANCEL',
   366→      secondaryButtonText: 'DELETE',
   367→      onSecondaryPress: async () => {
   368→        try {
   369→          const userId = auth.currentUser?.uid;
   370→          if (!userId) return;
   371→          await deleteDoc(doc(db, 'users', userId, 'habits', habitId));
   372→        } catch (error) {
   373→          console.error('Error deleting habit:', error);
   374→        }
   375→      },
   376→    } as any);
   377→  }, []);
   378→
   379→  const handleRefresh = useCallback(() => {
   380→    setRefreshing(true);
   381→  }, []);
   382→
   383→  // Navigate to Settings
   384→  const handleOpenSettings = useCallback(() => {
   385→    router.push('/settings');
   386→  }, [router]);
   387→
   388→  const completedCount = habits.filter(h => isCompletedToday(h)).length;
   389→  const totalCount = habits.length;
