    26→
    27→// ============== HELPERS ==============
    28→
    29→function getLocalDateString(date: Date = new Date()): string {
    30→  const year = date.getFullYear();
    31→  const month = String(date.getMonth() + 1).padStart(2, '0');
    32→  const day = String(date.getDate()).padStart(2, '0');
    33→  return `${year}-${month}-${day}`;
    34→}
    35→
    36→function getYesterdayDateString(): string {
    37→  const yesterday = new Date();
    38→  yesterday.setDate(yesterday.getDate() - 1);
    39→  return getLocalDateString(yesterday);
    40→}
    41→
    42→// ============== INTERFACES ==============
    43→
    44→interface Habit {
    45→  id: string;
    46→  name: string;
    47→  description: string;
    48→  currentStreak: number;
    49→  longestStreak: number;
    50→  totalCheckIns: number;
    51→  lastCheckIn?: string;
    52→  lastCheckInLocal?: string;
    53→}
    54→
    55→interface ModalState {
    56→  visible: boolean;
    57→  mood: 'pleased' | 'talking';
    58→  title: string;
    59→  message: string;
    60→  buttonText: string;
    61→  onCloseAction: 'stay' | 'goBack';
    62→}
    63→
    64→interface SuccessState {
    65→  visible: boolean;
    66→  streak: number;
    67→  habitName: string;
    68→  roastMessage: string;
    69→}
    70→
    71→// ============== STREAK LOGIC ==============
    72→
    73→function isCompletedToday(habit: Habit): boolean {
    74→  const today = getLocalDateString();
    75→  if (habit.lastCheckInLocal) return habit.lastCheckInLocal === today;
    76→  if (habit.lastCheckIn) return habit.lastCheckIn.split('T')[0] === today;
    77→  return false;
    78→}
    79→
    80→function isCompletedYesterday(habit: Habit): boolean {
    81→  const yesterday = getYesterdayDateString();
    82→  if (habit.lastCheckInLocal) return habit.lastCheckInLocal === yesterday;
    83→  if (habit.lastCheckIn) return habit.lastCheckIn.split('T')[0] === yesterday;
    84→  return false;
    85→}
    86→
    87→function calculateNewStreak(habit: Habit): number {
    88→  if (!habit.lastCheckIn && !habit.lastCheckInLocal) return 1;
    89→  if (isCompletedToday(habit)) return Math.max(habit.currentStreak, 1);
    90→  if (isCompletedYesterday(habit)) return habit.currentStreak + 1;
    91→  return 1;
    92→}
    93→
    94→// ============== WARM BUTTON COMPONENT ==============
    95→
    96→interface WarmButtonProps {
    97→  title: string;
    98→  onPress: () => void;
    99→  icon?: keyof typeof Ionicons.glyphMap;
   100→  variant?: 'primary' | 'secondary';
   101→  loading?: boolean;
   102→  disabled?: boolean;
   103→}
   104→
   105→function WarmButton({ title, onPress, icon, variant = 'primary', loading, disabled }: WarmButtonProps) {
   106→  const isPrimary = variant === 'primary';
   107→  
   108→  return (
   109→    <Pressable
   110→      style={({ pressed }) => [
   111→        buttonStyles.button,
   112→        isPrimary ? buttonStyles.primary : buttonStyles.secondary,
   113→        pressed && buttonStyles.pressed,
   114→        disabled && buttonStyles.disabled,
   115→      ]}
   116→      onPress={onPress}
   117→      disabled={disabled || loading}
   118→    >
   119→      {loading ? (
   120→        <ActivityIndicator color={isPrimary ? Colors.buttonPrimaryText : Colors.buttonSecondaryText} />
   121→      ) : (
   122→        <>
   123→          {icon && (
   124→            <Ionicons 
   125→              name={icon} 
   126→              size={20} 
   127→              color={isPrimary ? Colors.buttonPrimaryText : Colors.buttonSecondaryText} 
   128→              style={buttonStyles.icon}
   129→            />
   130→          )}
   131→          <Text style={[
   132→            buttonStyles.text,
   133→            isPrimary ? buttonStyles.primaryText : buttonStyles.secondaryText
   134→          ]}>
   135→            {title}
   136→          </Text>
   137→        </>
   138→      )}
   139→    </Pressable>
   140→  );
   141→}
   142→
   143→const buttonStyles = StyleSheet.create({
   144→  button: {
   145→    flexDirection: 'row',
   146→    alignItems: 'center',
   147→    justifyContent: 'center',
   148→    paddingVertical: Spacing.lg,
   149→    paddingHorizontal: Spacing.xl,
   150→    borderRadius: BorderRadius.button,
   151→    ...Shadows.button,
   152→  },
   153→  primary: {
   154→    backgroundColor: Colors.buttonPrimary,
   155→  },
   156→  secondary: {
   157→    backgroundColor: Colors.buttonSecondary,
   158→    borderWidth: 1,
   159→    borderColor: Colors.border,
   160→  },
   161→  pressed: {
   162→    opacity: 0.9,
   163→    transform: [{ scale: 0.98 }],
   164→  },
   165→  disabled: {
   166→    opacity: 0.5,
   167→  },
   168→  icon: {
   169→    marginRight: Spacing.sm,
   170→  },
   171→  text: {
   172→    fontSize: 14,
   173→    fontWeight: '700',
   174→    letterSpacing: 1,
   175→  },
   176→  primaryText: {
   177→    color: Colors.buttonPrimaryText,
   178→  },
   179→  secondaryText: {
   180→    color: Colors.buttonSecondaryText,
   181→  },
   182→});
   183→
   184→// ============== MAIN COMPONENT ==============
   185→
   186→export default function CheckInScreen() {
   187→  const { id, habitData } = useLocalSearchParams<{ id: string; habitData?: string }>();
   188→  const router = useRouter();
   189→  const functions = getFunctions();
   190→  const insets = useSafeAreaInsets();
   191→
   192→  // Parse habit data from params immediately (no loading needed)
   193→  const initialHabit = React.useMemo(() => {
   194→    if (habitData) {
   195→      try {
   196→        return JSON.parse(habitData) as Habit;
   197→      } catch {
   198→        return null;
   199→      }
   200→    }
   201→    return null;
   202→  }, [habitData]);
   203→
   204→  const [habit, setHabit] = useState<Habit | null>(initialHabit);
   205→  const [imageUri, setImageUri] = useState<string | null>(null);
   206→  const [loading, setLoading] = useState(!initialHabit); // Only load if no data passed
   207→  const [uploading, setUploading] = useState(false);
   208→  const [uploadProgress, setUploadProgress] = useState('');
   209→
   210→  const [modal, setModal] = useState<ModalState>({
   211→    visible: false,
   212→    mood: 'pleased',
   213→    title: '',
   214→    message: '',
   215→    buttonText: 'OK',
   216→    onCloseAction: 'stay',
   217→  });
   218→
   219→  const [success, setSuccess] = useState<SuccessState>({
   220→    visible: false,
   221→    streak: 0,
   222→    habitName: '',
   223→    roastMessage: '',
   224→  });
   225→
   226→  // Only fetch from Firestore if no habit data was passed (fallback)
   227→  useEffect(() => {
   228→    if (!initialHabit) {
   229→      loadHabit();
   230→    }
   231→  }, [id, initialHabit]);
   232→
   233→  const loadHabit = async () => {
   234→    try {
   235→      const userId = auth.currentUser?.uid;
   236→      if (!userId) return;
   237→
   238→      const habitRef = doc(db, 'users', userId, 'habits', id);
   239→      const habitSnap = await getDoc(habitRef);
   240→
   241→      if (habitSnap.exists()) {
   242→        setHabit({ id: habitSnap.id, ...habitSnap.data() } as Habit);
   243→      } else {
   244→        showModal('talking', 'ERROR', 'Habit not found.', 'GO BACK', 'goBack');
   245→      }
   246→    } catch (error) {
   247→      console.error('Error loading habit:', error);
   248→      showModal('talking', 'ERROR', 'Could not load habit data.', 'GO BACK', 'goBack');
   249→    } finally {
   250→      setLoading(false);
   251→    }
   252→  };
   253→
   254→  const showModal = (
   255→    mood: 'pleased' | 'talking',
   256→    title: string,
   257→    message: string,
   258→    buttonText: string = 'OK',
   259→    onCloseAction: 'stay' | 'goBack' = 'stay'
   260→  ) => {
   261→    setModal({ visible: true, mood, title, message, buttonText, onCloseAction });
   262→  };
   263→
   264→  const handleModalClose = () => {
   265→    const action = modal.onCloseAction;
   266→    setModal((prev) => ({ ...prev, visible: false }));
   267→    if (action === 'goBack') router.back();
   268→  };
   269→
   270→  const handleSuccessClose = () => {
   271→    setSuccess((prev) => ({ ...prev, visible: false }));
   272→    router.back();
   273→  };
   274→
   275→  const requestPermissions = async () => {
   276→    const { status: cameraStatus } = await ImagePicker.requestCameraPermissionsAsync();
   277→    const { status: mediaStatus } = await ImagePicker.requestMediaLibraryPermissionsAsync();
   278→
   279→    if (cameraStatus !== 'granted' || mediaStatus !== 'granted') {
   280→      showModal(
   281→        'talking',
   282→        'PERMISSION NEEDED',
   283→        'Camera and photo access required for verification.',
   284→        'GOT IT'
   285→      );
   286→      return false;
   287→    }
   288→    return true;
   289→  };
   290→
   291→  const takePhoto = async () => {
   292→    const hasPermission = await requestPermissions();
   293→    if (!hasPermission) return;
   294→
   295→    const result = await ImagePicker.launchCameraAsync({
   296→      allowsEditing: true,
   297→      aspect: [4, 3],
   298→      quality: 0.7,
   299→    });
   300→
   301→    if (!result.canceled) {
   302→      setImageUri(result.assets[0].uri);
   303→    }
   304→  };
   305→
   306→  const pickImage = async () => {
