    18→// ============== HELPERS ==============
    19→
    20→function getLocalDateString(date: Date = new Date()): string {
    21→  const year = date.getFullYear();
    22→  const month = String(date.getMonth() + 1).padStart(2, '0');
    23→  const day = String(date.getDate()).padStart(2, '0');
    24→  return `${year}-${month}-${day}`;
    25→}
    26→
    27→function getYesterdayDateString(): string {
    28→  const yesterday = new Date();
    29→  yesterday.setDate(yesterday.getDate() - 1);
    30→  return getLocalDateString(yesterday);
    31→}
    32→
    33→// ============== INTERFACES ==============
    34→
    35→interface Habit {
    36→  id: string;
    37→  name: string;
    38→  description: string;
    39→  currentStreak: number;
    40→  longestStreak: number;
    41→  totalCheckIns: number;
    42→  lastCheckIn?: string;
    43→  lastCheckInLocal?: string;
    44→}
    45→
    46→// ============== STREAK LOGIC ==============
    47→
    48→function isCompletedToday(habit: Habit): boolean {
    49→  const today = getLocalDateString();
    50→  if (habit.lastCheckInLocal) return habit.lastCheckInLocal === today;
    51→  if (habit.lastCheckIn) return habit.lastCheckIn.split('T')[0] === today;
    52→  return false;
    53→}
    54→
    55→function isCompletedYesterday(habit: Habit): boolean {
    56→  const yesterday = getYesterdayDateString();
    57→  if (habit.lastCheckInLocal) return habit.lastCheckInLocal === yesterday;
    58→  if (habit.lastCheckIn) return habit.lastCheckIn.split('T')[0] === yesterday;
    59→  return false;
    60→}
    61→
    62→function getDisplayStreak(habit: Habit): number {
    63→  if (isCompletedToday(habit)) return habit.currentStreak;
    64→  if (isCompletedYesterday(habit)) return habit.currentStreak;
    65→  return 0;
    66→}
