  appId: "1:11276683184:web:1e7fb27f5f0bd0b8417875",
  measurementId: "G-LTNNKTXCBP"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);

// Initialize Auth with AsyncStorage persistence
